using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 defaults to "$type" instead of "Discriminator".
            // Existing 500K docs use "Discriminator", and raw SQL queries
            // reference c.Discriminator, so we must keep the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — id format changed.
            // EF Core 9 stores id as the raw key value ("123").
            // Existing docs use the EF Core 8 format ("Product|123").
            // Opt back in to the legacy format to read existing data.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Preserve the EF Core 8 "EntityType|Key" id format globally
        configurationBuilder.Conventions.Add(_ =>
            new Microsoft.EntityFrameworkCore.Cosmos.Metadata.Conventions.CosmosNoSyntheticIdConvention());
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

