using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 defaults to "$type" instead of "Discriminator".
            // Existing 500K docs store "Discriminator":"Product" and raw SQL
            // queries reference c.Discriminator, so we must keep the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Id property now maps to JSON "id".
            // EF Core 8 synthesized the JSON id as "Product|123" and stored
            // the CLR Id separately as "Id":123.  EF Core 9 maps the CLR Id
            // directly to "id", which would collide with existing documents.
            // Restore the old layout: keep Id as a separate JSON property so
            // the provider falls back to the synthesized "Product|123" format.
            entity.Property(p => p.Id).ToJsonProperty("Id");

            // BREAKING CHANGE 3 — HasIndex removed.
            // The original code had HasIndex(p => p.Sku). Cosmos does not
            // support EF-managed indexes; it was silently ignored in EF8 but
            // is invalid in EF9. Cosmos indexing is configured via the Azure
            // Portal or Cosmos SDK indexing policy — removed here.
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

